90	var createCmd = &cobra.Command{
91		Use:     "create [name]",
92		Aliases: []string{"cr"},
93		Short:   "Create a new sandbox",
94		Long: `Create a new sandbox.
95	
96	If no name is provided, creates a temporary sandbox with an auto-generated name like "temp-<timestamp>".
97	
98	Environment variables can set defaults for commonly used flags:
99	  SANDCASTLE_HOME=1    equivalent to --home
100	  SANDCASTLE_DATA=.    equivalent to --data (value is the subpath, "." or "1" for root)
101	  SANDCASTLE_RM=1      equivalent to --rm
102	
103	Flags explicitly passed on the command line take precedence over environment variables.`,
104		Args: cobra.MaximumNArgs(1),
105		PreRun: func(cmd *cobra.Command, args []string) {
106			// Priority: explicit flag > env var > config preference
107			cfg, _ := config.Load()
108			prefs := cfg.LoadPreferences()
109	
110			if !cmd.Flags().Changed("home") {
111				if prefs.MountHome != nil && *prefs.MountHome {
112					sandboxHome = true
113				}
114			}
115			if !cmd.Flags().Changed("rm") && envTruthy("SANDCASTLE_RM") {
116				sandboxRemove = true
117			}
118			if !cmd.Flags().Changed("data") {
119				if prefs.DataPath != "" {
120					sandboxData = prefs.DataPath
121				}
122			}
123			if !cmd.Flags().Changed("no-vnc") {
124				if prefs.VNC != nil && !*prefs.VNC {
125					sandboxNoVNC = true
126				}
127			}
128			if !cmd.Flags().Changed("no-docker") {
129				if prefs.Docker != nil && !*prefs.Docker {
130					sandboxNoDocker = true
131				}
132			}
133		},
134		RunE: func(cmd *cobra.Command, args []string) error {
135			client, err := api.NewClient()
136			if err != nil {
137				return err
138			}
139			printServer(client)
140	
141			// Auto-generate name if not provided
142			var name string
143			autoGenerated := false
144			if len(args) == 0 {
145				name = fmt.Sprintf("temp-%d", time.Now().Unix())
146				autoGenerated = true
147				// Auto-generated sandboxes are temporary by default
148				if !cmd.Flags().Changed("rm") {
149					sandboxRemove = true
150				}
151			} else {
152				name = args[0]
153			}
154	
155			// Resolve snapshot flags: --from-snapshot takes precedence over --snapshot
156			fromSnap := sandboxFromSnapshot
157			if fromSnap == "" {
158				fromSnap = sandboxSnapshot
159			}
160	
161			var restoreLayers []string
162			if sandboxRestoreLayers != "" {
163				for _, l := range strings.Split(sandboxRestoreLayers, ",") {
164					restoreLayers = append(restoreLayers, strings.TrimSpace(l))
165				}
166			}
167			if sandboxStorage != "direct" && sandboxStorage != "snapshot" {
168				return fmt.Errorf("invalid storage mode %q: must be direct or snapshot", sandboxStorage)
169			}
170			if sandboxOIDC && sandboxNoOIDC {
171				return fmt.Errorf("--oidc and --no-oidc are mutually exclusive")
172			}
173			if sandboxNoOIDC && (sandboxGCP || sandboxGCPConfig != "" || sandboxGCPServiceAccount != "") {
174				return fmt.Errorf("--no-oidc cannot be used with GCP credential configuration")
175			}
176			if sandboxGCPScope != "sandbox" && sandboxGCPScope != "user" {
177				return fmt.Errorf("--gcp-scope must be sandbox or user")
178			}
179			var oidcEnabled *bool
180			if cmd.Flags().Changed("oidc") {
181				v := true
182				oidcEnabled = &v
183			}
184			if cmd.Flags().Changed("no-oidc") {
185				v := false
186				oidcEnabled = &v
187			}
188			var gcpConfigID int
189			if sandboxGCPConfig != "" {
190				config, err := findGcpConfig(client, sandboxGCPConfig)
191				if err != nil {
192					return err
193				}
194				gcpConfigID = config.ID
195			}
196			if oidcEnabled == nil && (sandboxGCP || sandboxGCPConfig != "" || sandboxGCPServiceAccount != "") {
197				v := true
198				oidcEnabled = &v
199			}
200	
201			if sandboxHome && sandboxHomeSubdir != "" {
202				return fmt.Errorf("--home and --home-subdir are mutually exclusive")
203			}
204			if sandboxProject != "" && sandboxProjectSubdir != "" {
205				return fmt.Errorf("--project and --project-subdir cannot be combined")
206			}
207	
208			req := api.CreateSandboxRequest{
209				Name:                   name,
210				Image:                  sandboxImage,
211				FromSnapshot:           fromSnap,
212				RestoreLayers:          restoreLayers,
213				Tailscale:              sandboxTailscale,
214				MountHome:              sandboxHome,
215				HomePath:               sandboxHomeSubdir,
216				DataPath:               sandboxData,
217				StorageMode:            sandboxStorage,
218				Temporary:              sandboxRemove,
219				VNCEnabled:             !sandboxNoVNC,
220				VNCGeometry:            sandboxVNCGeometry,
221				VNCDepth:               sandboxVNCDepth,
222				DockerEnabled:          !sandboxNoDocker,
223				SMBEnabled:             sandboxSMB,
224				OIDCEnabled:            oidcEnabled,
225				GCPOIDCEnabled:         sandboxGCP || sandboxGCPConfig != "" || sandboxGCPServiceAccount != "",
226				GCPOIDCConfigID:        gcpConfigID,
227				GCPServiceAccountEmail: sandboxGCPServiceAccount,
228				GCPPrincipalScope:      sandboxGCPScope,
229				GCPRoles:               cleanStringList(sandboxGCPRoles),
230			}
231			if sandboxProject != "" {
232				req.ProjectName = sandboxProject
233			}
234			if sandboxProjectSubdir != "" {
235				req.ProjectPath = sandboxProjectSubdir
236				req.HomePath = ""
237				req.MountHome = false
238				req.DataPath = ""
239			}
240			sandbox, err := client.CreateSandbox(req)
241			if err != nil {
242				return err
243			}
244	
245			if autoGenerated {
246				fmt.Printf("Sandbox %q created (auto-generated name).\n", sandbox.DisplayName())
247			} else {
248				fmt.Printf("Sandbox %q created.\n", sandbox.DisplayName())
249			}
250	
251			// Print active options (use local flags — they reflect what was actually requested)
252			if sandboxHome || sandboxHomeSubdir != "" || sandboxProject != "" || sandboxProjectSubdir != "" || sandboxData != "" || sandboxStorage != "direct" || sandbox.Tailscale || sandboxRemove || fromSnap != "" || sandboxNoVNC || sandboxVNCGeometry != "" || sandboxVNCDepth != 0 || sandboxNoDocker || sandboxSMB || sandboxGCP || sandboxGCPConfig != "" || sandboxGCPServiceAccount != "" {
253				if sandboxHome {
254					fmt.Println("  Home:      mounted (~/ persisted)")
255				}
256				if sandboxHomeSubdir != "" {
257					fmt.Printf("  Home:      mounted (%s → $HOME)\n", sandboxHomeSubdir)
258				}
259				if sandboxProject != "" {
260					fmt.Printf("  Project:   %s\n", sandboxProject)
261				}
262				if sandboxProjectSubdir != "" {
263					fmt.Printf("  Project:   %s (scoped home + persisted)\n", sandboxProjectSubdir)
264				}
265				if sandboxData != "" {
266					label := sandboxData
267					if label == "." {
268						label = "user data root"
269					}
270					fmt.Printf("  Data:      mounted (%s → /persisted)\n", label)
271				}
272				if sandboxStorage != "direct" {
273					fmt.Printf("  Storage:   %s\n", sandboxStorage)
274				}
275				if sandbox.Tailscale {
276					fmt.Println("  Tailscale: enabled")
277				}
278				if sandboxRemove {
279					fmt.Println("  Cleanup:   auto-remove on exit")
280				}
281				if fromSnap != "" {
282					fmt.Printf("  Snapshot:  restored from %q\n", fromSnap)
283				}
284				if sandboxNoDocker {
285					fmt.Println("  Docker:    disabled")
286				}
287				if sandboxNoVNC {
288					fmt.Println("  VNC:       disabled")
289				} else if sandboxVNCGeometry != "" || sandboxVNCDepth != 0 {
290					geom := sandbox.VNCGeometry
291					if geom == "" {
292						geom = "1280x900"
293					}
294					depth := sandbox.VNCDepth
295					if depth == 0 {
296						depth = 24
297					}
298					fmt.Printf("  VNC:       %s @ %d-bit\n", geom, depth)
299				}
300				if sandboxSMB {
301					fmt.Println("  SMB:       enabled")
302				}
303				if sandboxGCP || sandboxGCPConfig != "" || sandboxGCPServiceAccount != "" {
304					fmt.Println("  GCP:       configured")
305				}
306			}
307	
308			if sandboxNoConnect {
309				return nil
310			}
311	
312			info, err := client.ConnectInfo(sandbox.ID)
313			if err != nil {
314				return err
315			}
316	
317			if os.Getenv("VERBOSE") == "1" {
318				fmt.Fprintf(os.Stderr, "\033[2m[verbose] Connection info: host=%s port=%d user=%s\033[0m\n", info.Host, info.Port, info.User)
319				if info.TailscaleIP != "" {
320					fmt.Fprintf(os.Stderr, "\033[2m[verbose] Tailscale IP (Tailscale): %s\033[0m\n", info.TailscaleIP)
321				}
322			}
323	
324			if err := checkHostReachable(info.Host, info.Port); err != nil {
325				return err
326			}
327	
328			if err := waitForSSH(info.Host, info.Port); err != nil {
329				return err
330			}
331	
332			cfg, loadErr := config.Load()
333			if loadErr != nil {
334				return loadErr
335			}
336			prefs := cfg.LoadPreferences()
337	
338			var remoteCmd string
339			if *prefs.UseTmux {
340				remoteCmd = tmuxCmd
341			}
342	
343			var sshErr error
344			if pickProtocol(cfg, info.Host, info.Port, info.User, prefs.SSHExtraArgs) == "mosh" {
345				fmt.Fprintf(os.Stderr, "\033[33mWarning:\033[0m mosh does not support SSH agent forwarding. Use --mosh=no if you need ssh-add keys inside the sandbox.\n")
346				sshErr = moshExec(info.Host, info.Port, info.User, remoteCmd, prefs.SSHExtraArgs, nil)
347			} else {
348				sshErr = sshExec(info.Host, info.Port, info.User, remoteCmd, prefs.SSHExtraArgs, nil)
349			}
350	
351			if sandboxRemove {
352				// Re-fetch to check if user toggled to "keep" during the session
353				current, fetchErr := client.GetSandbox(sandbox.ID)
354				if fetchErr == nil && !current.Temporary {
355					fmt.Printf("Sandbox %q was set to keep — skipping removal.\n", sandbox.DisplayName())
356				} else {
357					fmt.Printf("Removing sandbox %q...\n", sandbox.DisplayName())
358					if err := client.DestroySandbox(sandbox.ID); err != nil {
359						fmt.Fprintf(os.Stderr, "Warning: failed to delete sandbox: %v\n", err)
360					} else {
361						fmt.Printf("Sandbox %q deleted.\n", sandbox.DisplayName())
362					}
363				}
364			}
365	
366			return sshErr
367		},
368	}
