389				}
390				w := tabwriter.NewWriter(os.Stdout, 0, 0, 2, ' ', 0)
391				fmt.Fprintln(w, "ID\tNAME\tARCHIVED\tCREATED\tIMAGE")
392				for _, s := range sandboxes {
393					archivedAt := ""
394					if s.ArchivedAt != nil {
395						archivedAt = s.ArchivedAt.Local().Format("2006-01-02 15:04")
396					}
397					created := s.CreatedAt.Local().Format("2006-01-02 15:04")
398					fmt.Fprintf(w, "%d\t%s\t%s\t%s\t%s\n", s.ID, s.DisplayName(), archivedAt, created, s.Image)
399				}
400				w.Flush()
401				return nil
402			}
403	
404			sandboxes, err := client.ListSandboxes()
405			if err != nil {
406				return err
407			}
408	
409			if len(sandboxes) == 0 {
410				fmt.Println("No sandboxes.")
411				return nil
412			}
413	
414			hasRoute := false
415			hasProject := false
416			for _, s := range sandboxes {
417				if len(s.Routes) > 0 {
418					hasRoute = true
419				}
420				if s.ProjectName != "" {
421					hasProject = true
422				}
423			}
424			dnsNames := dnsNamesBySandboxID(client)
425			hasDNS := len(dnsNames) > 0
426	
427			w := tabwriter.NewWriter(os.Stdout, 0, 0, 2, ' ', 0)
428	
429			headers := []string{"NAME"}
430			if hasProject {
431				headers = append(headers, "PROJECT")
432			}
433			headers = append(headers, "STATUS", "CREATED")
434			if hasRoute {
435				headers = append(headers, "ROUTE")
436			}
437			if hasDNS {
438				headers = append(headers, "DNS")
439			}
440			headers = append(headers, "TAILSCALE IP", "IMAGE AGE")
441			fmt.Fprintln(w, strings.Join(headers, "\t"))
442	
443			for _, s := range sandboxes {
444				name := s.Name
445				if s.Temporary {
446					name += " (temp)"
447				}
448				tsIP := s.TailscaleIP
449				created := s.CreatedAt.Local().Format("2006-01-02 15:04")
450				imageAge := formatImageAge(s.ImageBuiltAt)
451	
452				cols := []string{name}
453				if hasProject {
454					cols = append(cols, s.ProjectName)
455				}
456				cols = append(cols, s.Status, created)
457				if hasRoute {
458					route := ""
459					if len(s.Routes) > 0 {
460						parts := make([]string, len(s.Routes))
461						for i, r := range s.Routes {
462							parts[i] = fmt.Sprintf("%s (:%d)", r.URL, r.Port)
463						}
464						route = strings.Join(parts, ", ")
465					}
466					cols = append(cols, route)
467				}
468				if hasDNS {
469					cols = append(cols, dnsNames[s.ID])
470				}
471				cols = append(cols, tsIP, imageAge)
472				fmt.Fprintln(w, strings.Join(cols, "\t"))
473			}
474			w.Flush()
475			return nil
476		},
477	}
