479	func dnsNamesBySandboxID(client *api.Client) map[int]string {
480		status, err := client.DNSStatus()
481		if err != nil || status == nil || len(status.Records) == 0 {
482			return nil
483		}
484	
485		names := make(map[int]string, len(status.Records))
486		for _, record := range status.Records {
487			if record.SandboxID == 0 || record.Name == "" {
488				continue
489			}
490			names[record.SandboxID] = record.Name
491		}
492		return names
493	}
