785	
786	// formatImageAge returns a human-readable image age string (e.g. "2h ago", "3d ago").
787	// Returns "-" when the build timestamp is not available.
788	func formatImageAge(builtAt *time.Time) string {
789		if builtAt == nil {
790			return "-"
791		}
792		d := time.Since(*builtAt)
793		switch {
794		case d < time.Minute:
795			return "just now"
796		case d < time.Hour:
797			return fmt.Sprintf("%dm ago", int(d.Minutes()))
798		case d < 24*time.Hour:
799			return fmt.Sprintf("%dh ago", int(d.Hours()))
800		default:
801			return fmt.Sprintf("%dd ago", int(d.Hours()/24))
802		}
803	}
